+            sequence: 1,
+            component: "stdlib",
+            event: "string_slice_receipt",
+            outcome: "pass",
+            error_code: None,
+            timing_us: 11,
+            timestamp_unix_ms: 1_700_000_004_121,
+        }),
+        context.event(EventInput {
+            sequence: 2,
+            component: "stdlib",
+            event: "string_concat_receipt",
+            outcome: "pass",
+            error_code: None,
+            timing_us: 17,
+            timestamp_unix_ms: 1_700_000_004_122,
