+        ),
+    ];
+    let run_id = context.default_run_id();
+    let manifest = HarnessRunManifest::from_context(
+        &context,
+        &run_id,
+        events.len(),
+        commands.len(),
+        "cargo test --test stdlib_integration string_representation_scenario_emits_artifact_triad_and_reports",
+        1_700_000_004_199,
+    );
